code = """import json

# Get all businesses accepting credit cards
businesses = locals().get('var_functions.query_db:18', [])
reviews = locals().get('var_functions.query_db:20', [])

# Process businesses to extract categories
business_category_map = {}
for business in businesses:
    business_id = business['business_id']
    business_ref = business_id.replace('businessid_', 'businessref_')
    description = business.get('description', '')
    
    categories = []
    if 'services in' in description:
        cat_part = description.split('services in')[1].split('.')[0]
        cat_part = cat_part.replace(' and ', ', ')
        categories = [cat.strip() for cat in cat_part.split(',') if cat.strip()]
    elif 'fields of' in description:
        cat_part = description.split('fields of')[1].split('.')[0]
        cat_part = cat_part.replace(' and ', ', ')
        categories = [cat.strip() for cat in cat_part.split(',') if cat.strip()]
    
    business_category_map[business_ref] = categories

# Find reviews for these businesses
business_ratings = {}
for review in reviews:
    business_ref = review['business_ref']
    if business_ref in business_category_map:
        rating = int(review['rating'])
        if business_ref not in business_ratings:
            business_ratings[business_ref] = []
        business_ratings[business_ref].append(rating)

# Organize by category
category_stats = {}
for business_ref, categories in business_category_map.items():
    if business_ref in business_ratings:
        ratings = business_ratings[business_ref]
        for category in categories:
            if category not in category_stats:
                category_stats[category] = {'count': 0, 'ratings': []}
            category_stats[category]['count'] += 1
            category_stats[category]['ratings'].extend(ratings)

# Calculate averages
category_averages = {}
for category, stats in category_stats.items():
    if stats['ratings']:
        category_averages[category] = {
            'business_count': stats['count'],
            'avg_rating': sum(stats['ratings']) / len(stats['ratings'])
        }

# Sort by business count
sorted_categories = sorted(category_averages.items(), key=lambda x: x[1]['business_count'], reverse=True)

result = {
    'categories_found': len(sorted_categories),
    'sample_results': sorted_categories[:5]
}

print('__RESULT__:')
print(json.dumps(result))"""

